def _find_brand_asset(kind: str) -> Path | None:
    for filename in _BRAND_ASSET_NAMES[kind]:
        candidate = BRAND_ASSET_DIR / filename
        if candidate.exists():
            return candidate
    return None


def _asset_to_src(path: Path | None) -> str | None:
    if path is None:
        return None
    suffix = path.suffix.lower()
    if suffix == ".svg":
        mime = "image/svg+xml"
    elif suffix in {".jpg", ".jpeg"}:
        mime = "image/jpeg"
    elif suffix == ".png":
        mime = "image/png"
    else:
        return None
    return f"data:{mime};base64,{base64.b64encode(path.read_bytes()).decode('ascii')}"


def _load_page_icon(path: Path | None):
    if Image is not None and path is not None:
        try:
            return Image.open(path)
        except Exception:
            pass
    return "T"


_LOGO_ICON_PATH = _find_brand_asset("icon")
_LOGO_WORDMARK_PATH = _find_brand_asset("wordmark")
_LOGO_ICON_SRC = _asset_to_src(_LOGO_ICON_PATH)
_LOGO_WORDMARK_SRC = _asset_to_src(_LOGO_WORDMARK_PATH)
_PAGE_ICON = _load_page_icon(_LOGO_ICON_PATH)

