# ════════════════════════════════════════════════════════════════════
# PARSERS — Teambuildr specific formats
# ════════════════════════════════════════════════════════════════════

def parse_xlsx_questionnaire(file_bytes: bytes, mode: str = "rpe") -> pd.DataFrame:
    """
    Parsea los questionnaire-report de Teambuildr.
    Formato especial: athlete name row + dates as rows, values pivotadas.
    
    mode='rpe'      → extrae RPE + Time → calcula sRPE
    mode='wellness' → extrae Sueño + Estrés + Dolor
    """
    rows = _read_xlsx_rows(file_bytes)

    # Detectar bloques de atletas (row con solo un nombre no-fecha)
    records = []
    current_athlete = None

    for row in rows:
        if not row or all(v in ("", "-", None) for v in row):
            continue

        first = str(row[0]).strip()
        is_date = bool(_DATE_RE.match(first))

        # ¿Es nombre de atleta? (no es header, no es fecha TB, tiene letras)
        if (first not in ("Name", "Athlete") and
                not is_date and
                len(row) > 1 and
                any(c.isalpha() for c in first)):
            current_athlete = first
            continue

        # ¿Es fila de datos (fecha)?
        if current_athlete and is_date:
            try:
                date = pd.to_datetime(first, format="%b %d, %Y")
            except Exception:
                continue

            vals = [v for v in row[1:] if v not in ("", "-", None, "Range Average")]

            if mode == "rpe":
                # Cols esperadas: RPE, Time, Total Score (tomamos pos 0 y 1 de vals)
                rpe_val  = _safe_float(vals[0]) if len(vals) > 0 else None
                time_val = _safe_float(vals[1]) if len(vals) > 1 else None
                if rpe_val is not None:
                    srpe = rpe_val * time_val if time_val else None
                    records.append({
                        "Date": date,
                        "Athlete": current_athlete,
                        "RPE": rpe_val,
                        "Duration_min": time_val,
                        "sRPE": srpe,
                    })

            elif mode == "wellness":
                # Cols: Sueño, Estrés, Dolor (tomamos pos 0,1,2)
                sueno  = _safe_float(vals[0]) if len(vals) > 0 else None
                estres = _safe_float(vals[1]) if len(vals) > 1 else None
                dolor  = _safe_float(vals[2]) if len(vals) > 2 else None
                if any(v is not None for v in [sueno, estres, dolor]):
                    records.append({
                        "Date": date,
                        "Athlete": current_athlete,
                        "Sueno_hs": sueno,
                        "Estres": estres,
                        "Dolor": dolor,
                        "Wellness_Score": _wellness_score(sueno, estres, dolor),
                    })

    return pd.DataFrame(records)


def parse_completion_report(file) -> pd.DataFrame:
    df = _read_csv_with_fallback(file)
    df.columns = [c.strip().strip('"') for c in df.columns]
    date_col = next((c for c in ["Dates", "Date", "Fecha"] if c in df.columns), None)
    assigned_col = next((c for c in ["Assigned", "Asignado"] if c in df.columns), None)
    completed_col = next((c for c in ["Completed", "Completado"] if c in df.columns), None)
    if not date_col or not assigned_col or not completed_col:
        raise ValueError("El Completion Report no tiene las columnas esperadas.")
    df["Date"] = pd.to_datetime(df[date_col], errors="coerce")
    df["Assigned"]  = pd.to_numeric(df[assigned_col],  errors="coerce")
    df["Completed"] = pd.to_numeric(df[completed_col], errors="coerce")
    df["Pct"] = df["Completed"] / df["Assigned"] * 100
    return df.dropna(subset=["Date"])


def parse_rep_load_report(file) -> pd.DataFrame:
    df = _read_csv_with_fallback(file)
    df.columns = [c.strip().strip('"') for c in df.columns]
    rename_map = {}
    if date_col := next((c for c in ["Date", "Dates", "Fecha"] if c in df.columns), None):
        rename_map[date_col] = "Date"
    if reps_assigned_col := next((c for c in ["Rep Count (Assigned)", "Assigned Reps", "Reps Assigned"] if c in df.columns), None):
        rename_map[reps_assigned_col] = "Reps_Assigned"
    if reps_completed_col := next((c for c in ["Rep Count (Completed)", "Completed Reps", "Reps Completed"] if c in df.columns), None):
        rename_map[reps_completed_col] = "Reps_Completed"
    if load_col := next((c for c in ["Load (Completed)", "Load Completed", "Load", "Weight"] if c in df.columns), None):
        rename_map[load_col] = "Load_kg"
    if athlete_col := next((c for c in ["Athlete", "Name", "Player", "Atleta"] if c in df.columns), None):
        rename_map[athlete_col] = "Athlete"
    if exercise_col := next((c for c in ["Exercise Name", "Exercise", "Ejercicio"] if c in df.columns), None):
        rename_map[exercise_col] = "Exercise"

    df = df.rename(columns=rename_map)
    if "Date" not in df.columns:
        raise ValueError("El Rep/Load Report no tiene una columna de fecha reconocible.")

    df["Date"] = pd.to_datetime(df["Date"], dayfirst=False, errors="coerce")
    if "Load_kg" in df.columns:
        df["Load_kg"] = pd.to_numeric(df["Load_kg"].astype(str).str.replace("--",""), errors="coerce")
    if "Reps_Completed" in df.columns:
        df["Reps_Completed"] = pd.to_numeric(df["Reps_Completed"].astype(str).str.replace("--",""), errors="coerce")
    if "Athlete" in df.columns:
        df["Athlete"] = df["Athlete"].astype(str).str.strip().str.title()
    return df.dropna(subset=["Date"])


def _normalize_eur_series_to_ratio(series: pd.Series) -> pd.Series:
    """Normaliza EUR a ratio CMJ/SJ."""
    s = pd.to_numeric(series, errors="coerce")
    mask_pct = s > 5
    s.loc[mask_pct] = 1 + (s.loc[mask_pct] / 100)
    return s.round(3)


def _read_csv_with_fallback(file, **kwargs) -> pd.DataFrame:
    """Lee CSVs con fallback de encoding para exports de TeamBuildr."""
    if isinstance(file, (str, os.PathLike, Path)):
        return pd.read_csv(file, **kwargs)

    raw_bytes = None
    if hasattr(file, "getvalue"):
        raw_bytes = file.getvalue()
    elif hasattr(file, "read"):
        raw_bytes = file.read()
        if hasattr(file, "seek"):
            file.seek(0)

    if raw_bytes is None:
        return pd.read_csv(file, **kwargs)

    if isinstance(raw_bytes, str):
        raw_bytes = raw_bytes.encode("utf-8")

    encodings = ("utf-8", "utf-8-sig", "cp1252", "latin-1")
    first_error = None

    for encoding in encodings:
        try:
            return pd.read_csv(BytesIO(raw_bytes), encoding=encoding, **kwargs)
        except (UnicodeDecodeError, pd.errors.ParserError, pd.errors.EmptyDataError) as exc:
            if first_error is None:
                first_error = exc

    sniff_kwargs = dict(kwargs)
    sniff_kwargs.setdefault("sep", None)
    sniff_kwargs.setdefault("engine", "python")
    for encoding in encodings:
        try:
            return pd.read_csv(BytesIO(raw_bytes), encoding=encoding, **sniff_kwargs)
        except (UnicodeDecodeError, pd.errors.ParserError, pd.errors.EmptyDataError):
            continue

    filename = getattr(file, "name", "archivo CSV")
    raise ValueError(
        f"No se pudo leer {filename} como CSV. "
        "Probé UTF-8, UTF-8-SIG, CP1252 y Latin-1."
    ) from first_error


def _legacy_parse_raw_workouts_unused(file) -> pd.DataFrame:
    df = _read_csv_with_fallback(file)
    df.columns = [c.strip().strip('"') for c in df.columns]
    df["Assigned Date"] = pd.to_datetime(df["Assigned Date"], errors="coerce")
    df["Result"] = pd.to_numeric(df["Result"], errors="coerce")
    df["Reps"]   = pd.to_numeric(df["Reps"],   errors="coerce")
    df["Volume_Load"] = df["Result"] * df["Reps"]
    df["Category"] = df["Tags"].map(TAG_CATEGORIES).fillna("Sin categoría")
    return df.dropna(subset=["Assigned Date"])


