def _read_forceplate_xlsx(file_bytes: bytes) -> dict:
    """
    Lee un archivo de plataforma de fuerza en formato transpuesto.
    Retorna dict: {metric_name: [rep1_val, rep2_val, ...]}
    """
    with zipfile.ZipFile(BytesIO(file_bytes)) as z:
        ns = "http://schemas.openxmlformats.org/spreadsheetml/2006/main"
        with z.open("xl/sharedStrings.xml") as f:
            ss_tree = ET.parse(f)
            strings = [
                "".join(t.text or "" for t in si.findall(f".//{{{ns}}}t"))
                for si in ss_tree.findall(f".//{{{ns}}}si")
            ]
        with z.open("xl/worksheets/sheet1.xml") as f:
            tree = ET.parse(f)
            raw_rows = []
            for row in tree.findall(f".//{{{ns}}}row"):
                cells = []
                for c in row.findall(f"{{{ns}}}c"):
                    t = c.get("t", "")
                    v_el = c.find(f"{{{ns}}}v")
                    if v_el is None:
                        cells.append(None)
                    elif t == "s":
                        idx = int(v_el.text)
                        cells.append(strings[idx] if idx < len(strings) else None)
                    else:
                        try:
                            cells.append(float(v_el.text))
                        except Exception:
                            cells.append(v_el.text)
                raw_rows.append(cells)

    result = {}
    for row in raw_rows[1:]:  # skip header row (References | Rep 1 | Rep 2...)
        if not row or not row[0]:
            continue
        metric = str(row[0]).strip()
        nums = []
        for v in row[1:]:
            if v is None or v == "":
                continue
            try:
                nums.append(float(v))
            except Exception:
                pass
        if nums:
            result[metric] = nums
    return result


def _extract_best(values: list, agg: str) -> float:
    """Extrae el mejor valor según la estrategia: max, min, mean."""
    if not values:
        return None
    if agg == "max":
        return round(max(values), 3)
    if agg == "min":
        return round(min(values), 3)
    return round(sum(values) / len(values), 3)


def parse_forceplate_file(file_bytes: bytes, test_type: str) -> dict:
    """
    Parsea un archivo de plataforma de fuerza y retorna dict con KPIs.
    test_type: 'CMJ' | 'SJ' | 'DJ' | 'IMTP'
    """
    raw = _read_forceplate_xlsx(file_bytes)
    metric_map = TEST_MAPS.get(test_type, {})
    result = {"test_type": test_type}
    for metric_name, (col_name, agg) in metric_map.items():
        if metric_name in raw:
            result[col_name] = _extract_best(raw[metric_name], agg)
            result[f"{col_name}_reps"] = raw[metric_name]  # guardar todas las reps
    return result


def parse_jump_eval(file) -> pd.DataFrame:
    """
    Wrapper de compatibilidad — para archivos CSV/Excel en formato
    tabular estándar (Date, Athlete, CMJ_cm, ...).
    Los archivos de plataforma se manejan con parse_forceplate_file.
    """
    name = file.name.lower() if hasattr(file, "name") else ""
    if name.endswith(".csv"):
        df = _read_csv_with_fallback(file)
    else:
        df = pd.read_excel(file)
    df.columns = [c.strip() for c in df.columns]
    df["Date"] = pd.to_datetime(
        df.get("Date", df.get("Fecha", pd.Timestamp.today())),
        dayfirst=True, errors="coerce"
    )
    numeric = ["CMJ_cm", "SJ_cm", "DJ_cm", "DJ_tc_ms", "IMTP_N"]
    for c in numeric:
        if c in df.columns:
            df[c] = pd.to_numeric(df[c], errors="coerce")
    return df


