def calc_acwr(srpe_series: pd.Series, dates: pd.DatetimeIndex,
              method="ewma") -> pd.DataFrame:
    """ACWR clásico (7:28) y EWMA. Retorna DataFrame diario."""
    daily = pd.Series(srpe_series.values, index=dates).sort_index()
    daily = daily.resample("D").sum().fillna(0)

    result = pd.DataFrame({"Date": daily.index, "sRPE_diario": daily.values})

    # Clásico
    result["Aguda_7d"]   = result["sRPE_diario"].rolling(7,  min_periods=1).mean()
    result["Cronica_28d"] = result["sRPE_diario"].rolling(28, min_periods=1).mean()
    result["ACWR_Classic"] = np.where(
        result["Cronica_28d"] > 0,
        result["Aguda_7d"] / result["Cronica_28d"], 0)

    # EWMA (Williams et al. 2017)
    result["EWMA_Aguda"]   = result["sRPE_diario"].ewm(alpha=0.28, adjust=False).mean()
    result["EWMA_Cronica"] = result["sRPE_diario"].ewm(alpha=0.07, adjust=False).mean()
    result["ACWR_EWMA"] = np.where(
        result["EWMA_Cronica"] > 0,
        result["EWMA_Aguda"] / result["EWMA_Cronica"], 0)

    result["ACWR"] = result["ACWR_EWMA"] if method == "ewma" else result["ACWR_Classic"]
    result["Zona"] = result["ACWR"].apply(_classify_acwr)
    result["Zona_Color"] = result["ACWR"].apply(lambda x: _acwr_color(x))
    return result


def calc_monotony_strain(srpe_daily: pd.DataFrame) -> pd.DataFrame:
    """Foster 2001: Monotonía y Strain semanal."""
    weekly = srpe_daily.set_index("Date")["sRPE_diario"].resample("W").agg(
        ["sum", "mean", "std"]).reset_index()
    weekly.columns = ["Semana", "Carga_Total", "Media", "SD"]
    weekly["SD"] = weekly["SD"].fillna(0.001)
    weekly["Monotonia"] = weekly["Media"] / weekly["SD"]
    weekly["Strain"] = weekly["Carga_Total"] * weekly["Monotonia"]
    weekly["Alerta"] = weekly["Monotonia"] > MONOTONY_HIGH
    return weekly


def _legacy_calc_eur_percentage_unused(df: pd.DataFrame) -> pd.DataFrame:
    """EUR = (CMJ - SJ) / SJ × 100. Bosco 1982."""
    if "CMJ_cm" in df.columns and "SJ_cm" in df.columns:
        df["EUR"] = ((df["CMJ_cm"] - df["SJ_cm"]) / df["SJ_cm"]) * 100
    return df


def calc_dri(df: pd.DataFrame) -> pd.DataFrame:
    """DRI = height_m / TC_s. Young 1995; Flanagan & Comyns 2008."""
    if "DJ_cm" in df.columns and "DJ_tc_ms" in df.columns:
        df["DRI"] = (df["DJ_cm"] / 100) / (df["DJ_tc_ms"] / 1000)
    return df


def calc_zscores(df: pd.DataFrame) -> pd.DataFrame:
    """
    Z-scores grupales para radar.
    DJ_tc_ms invertido: menor TC = mejor reactividad.
    """
    cols_config = {
        "CMJ_cm":   ("CMJ_Z",    False),
        "SJ_cm":    ("SJ_Z",     False),
        "DJ_tc_ms": ("DJtc_Z",   True),   # invertido
        "EUR":      ("EUR_Z",    False),
        "DRI":      ("DRI_Z",    False),
        "IMTP_N":   ("IMTP_Z",   False),
    }
    for col, (z_col, invert) in cols_config.items():
        if col in df.columns:
            vals = df[col].dropna()
            if len(vals) > 1 and vals.std() > 0:
                z = (df[col] - vals.mean()) / vals.std()
                df[z_col] = (-z if invert else z).round(2)
            else:
                df[z_col] = 0.0
    return df


def _legacy_calc_eur_from_records_unused(df: pd.DataFrame) -> pd.DataFrame:
    """
    Calcula EUR agrupando registros CMJ y SJ del mismo atleta y fecha.
    EUR = (CMJ_cm - SJ_cm) / SJ_cm × 100  (Bosco 1982)

    Si no hay datos de SJ, no crashea — EUR queda como NaN.
    Se puede completar después agregando el test SJ y reprocesando.
    """
    # Caso 1: CMJ y SJ ya están como columnas en el mismo df
    if "CMJ_cm" in df.columns and "SJ_cm" in df.columns:
        mask = df["CMJ_cm"].notna() & df["SJ_cm"].notna() & (df["SJ_cm"] != 0)
        df.loc[mask, "EUR"] = (
            (df.loc[mask, "CMJ_cm"] - df.loc[mask, "SJ_cm"])
            / df.loc[mask, "SJ_cm"] * 100
        ).round(2)
        return df

    # Caso 2: CMJ y SJ en filas separadas (test_type column)
    if "test_type" not in df.columns:
        return df  # sin info de tipo de test, no se puede calcular

    has_cmj_col = "CMJ_cm" in df.columns
    has_sj_col  = "SJ_cm"  in df.columns

    # Extraer filas CMJ — solo si la columna existe
    cmj_rows = pd.DataFrame()
    if has_cmj_col:
        cmj_mask = df["test_type"] == "CMJ"
        if cmj_mask.any():
            cmj_rows = df.loc[cmj_mask, ["Athlete", "Date", "CMJ_cm"]].dropna(subset=["CMJ_cm"])

    # Extraer filas SJ — solo si la columna existe
    sj_rows = pd.DataFrame()
    if has_sj_col:
        sj_mask = df["test_type"] == "SJ"
        if sj_mask.any():
            sj_rows = df.loc[sj_mask, ["Athlete", "Date", "SJ_cm"]].dropna(subset=["SJ_cm"])

    # Calcular EUR solo si tenemos ambos
    if not cmj_rows.empty and not sj_rows.empty:
        merged = cmj_rows.merge(sj_rows, on=["Athlete", "Date"], how="inner")
        if not merged.empty and (merged["SJ_cm"] != 0).any():
            merged["EUR"] = (
                (merged["CMJ_cm"] - merged["SJ_cm"]) / merged["SJ_cm"] * 100
            ).round(2)
            df = df.merge(
                merged[["Athlete", "Date", "EUR"]],
                on=["Athlete", "Date"], how="left"
            )

    # Si EUR no existe todavía, crear columna vacía
    if "EUR" not in df.columns:
        df["EUR"] = np.nan

    return df


def _legacy_calc_nm_profile_unused(df: pd.DataFrame) -> pd.DataFrame:
    """Perfil neuromuscular 4-cuadrantes basado en EUR + DRI."""
    if "EUR" not in df.columns or "DRI" not in df.columns:
        return df
    conditions = [
        (df["EUR"] >= 20) & (df["DRI"] >= 1.5),
        (df["EUR"] >= 20) & (df["DRI"] <  1.5),
        (df["EUR"] <  20) & (df["DRI"] >= 1.5),
        (df["EUR"] <  20) & (df["DRI"] <  1.5),
    ]
    labels = [
        "Reactivo-Elastico",
        "Elastico / CEA-Lento",
        "Reactivo / Poca Base 🟠",
        "Fuerza-Concentrica",
    ]
    df["NM_Profile"] = np.select(conditions, labels, default="Sin datos")
    return df


def parse_raw_workouts(file) -> pd.DataFrame:
    """Version robusta: tolera variantes de columnas y normaliza Athlete."""
    df = _read_csv_with_fallback(file)
    df.columns = [c.strip().strip('"') for c in df.columns]
    date_col = next((c for c in ["Assigned Date", "Date", "Workout Date", "Fecha"] if c in df.columns), None)
    athlete_col = next((c for c in ["Athlete", "Name", "Player", "Athlete Name", "Atleta"] if c in df.columns), None)
    result_col = next((c for c in ["Result", "Load", "Weight", "Carga"] if c in df.columns), None)
    reps_col = next((c for c in ["Reps", "Rep Count", "Completed Reps"] if c in df.columns), None)
    tags_col = next((c for c in ["Tags", "Tag", "Labels"] if c in df.columns), None)
    if not date_col or not result_col or not reps_col:
        raise ValueError("El Raw Data Report no tiene las columnas minimas esperadas.")

    rename_map = {
        date_col: "Assigned Date",
        result_col: "Result",
        reps_col: "Reps",
    }
    if athlete_col:
        rename_map[athlete_col] = "Athlete"
    if tags_col:
        rename_map[tags_col] = "Tags"

    df = df.rename(columns=rename_map)
    df["Assigned Date"] = pd.to_datetime(df["Assigned Date"], errors="coerce")
    df["Result"] = pd.to_numeric(df["Result"], errors="coerce")
    df["Reps"] = pd.to_numeric(df["Reps"], errors="coerce")
    df["Volume_Load"] = df["Result"] * df["Reps"]
    if "Athlete" in df.columns:
        df["Athlete"] = df["Athlete"].astype(str).str.strip().str.title()
    df["Category"] = df.get("Tags", pd.Series(index=df.index, dtype=object)).map(TAG_CATEGORIES).fillna("Sin categoria")
    return df.dropna(subset=["Assigned Date"])


def parse_maxes_health(file) -> pd.DataFrame:
    """Version robusta: normaliza atleta y ejercicio para visualizacion y reporte."""
    df = _read_csv_with_fallback(file)
    df.columns = [c.strip().strip('"') for c in df.columns]
    date_col = next((c for c in ["Added Date", "Date", "Fecha"] if c in df.columns), None)
    value_col = next((c for c in ["Max Value", "Value", "Peso", "Weight"] if c in df.columns), None)
    athlete_col = next((c for c in ["Athlete", "Name", "Player", "Atleta"] if c in df.columns), None)
    first_name_col = next((c for c in ["First Name", "Nombre"] if c in df.columns), None)
    last_name_col = next((c for c in ["Last Name", "Apellido"] if c in df.columns), None)
    exercise_col = next((c for c in ["Exercise Name", "Exercise", "Ejercicio"] if c in df.columns), None)
    if not date_col or not value_col:
        raise ValueError("El reporte de maximos no tiene fecha o valor maximo reconocible.")

    df["Added Date"] = pd.to_datetime(df[date_col], errors="coerce")
    df["Max Value"] = pd.to_numeric(df[value_col], errors="coerce")
    if athlete_col:
        df["Athlete"] = df[athlete_col].astype(str).str.strip().str.title()
    elif first_name_col and last_name_col:
        df["Athlete"] = (
            df[first_name_col].astype(str).str.strip()
            + " "
            + df[last_name_col].astype(str).str.strip()
        ).str.strip().str.title()
    else:
        df["Athlete"] = "Sin atleta"
    if exercise_col:
        df["Exercise Name"] = df[exercise_col]
    return df


def calc_eur(df: pd.DataFrame) -> pd.DataFrame:
    """EUR canonico = ratio CMJ/SJ."""
    if "CMJ_cm" in df.columns and "SJ_cm" in df.columns:
        mask = df["CMJ_cm"].notna() & df["SJ_cm"].notna() & (df["SJ_cm"] != 0)
        df.loc[mask, "EUR"] = (df.loc[mask, "CMJ_cm"] / df.loc[mask, "SJ_cm"]).round(3)
        if "EUR" in df.columns:
            df["EUR"] = _normalize_eur_series_to_ratio(df["EUR"])
    return df


def _calc_eur_from_records(df: pd.DataFrame) -> pd.DataFrame:
    """Compatibilidad: normaliza EUR a ratio CMJ/SJ."""
    if "EUR" in df.columns:
        df["EUR"] = _normalize_eur_series_to_ratio(df["EUR"])
    return calc_eur(df)


def calc_nm_profile(df: pd.DataFrame) -> pd.DataFrame:
    """Perfil neuromuscular usando EUR ratio y DRI."""
    if "EUR" not in df.columns or "DRI" not in df.columns:
        return df
    eur_ratio = _normalize_eur_series_to_ratio(df["EUR"])
    conditions = [
        (eur_ratio >= 1.20) & (df["DRI"] >= 1.5),
        (eur_ratio >= 1.20) & (df["DRI"] <  1.5),
        (eur_ratio <  1.20) & (df["DRI"] >= 1.5),
        (eur_ratio <  1.20) & (df["DRI"] <  1.5),
    ]
    labels = [
        "Reactivo-Elastico",
        "Elastico / CEA-Lento",
        "Reactivo / Poca Base",
        "Fuerza-Concentrica",
    ]
    df["EUR"] = eur_ratio
    df["NM_Profile"] = np.select(conditions, labels, default="Sin datos")
    return df


def _prepare_jump_df(jump_df: pd.DataFrame) -> pd.DataFrame:
    """Normaliza y recalcula metricas derivadas para la fuente unica de evaluaciones."""
    if jump_df is None or jump_df.empty:
        return pd.DataFrame()

    jump_df = jump_df.copy()
    if "Athlete" in jump_df.columns:
        jump_df["Athlete"] = jump_df["Athlete"].astype(str).str.strip().str.title()
    if "Date" in jump_df.columns:
        jump_df["Date"] = pd.to_datetime(jump_df["Date"], errors="coerce").dt.normalize()

    for col in [c for c in jump_df.columns if c not in {"Athlete", "Date", "NM_Profile"}]:
        jump_df[col] = pd.to_numeric(jump_df[col], errors="coerce")

    jump_df = jump_df.dropna(subset=[c for c in ["Athlete", "Date"] if c in jump_df.columns])
    if jump_df.empty:
        return pd.DataFrame()

    jump_df = jump_df.sort_values(["Athlete", "Date"]).drop_duplicates(
        subset=["Athlete", "Date"],
        keep="last",
    )
    jump_df = calc_eur(jump_df)
    jump_df = calc_dri(jump_df)
    jump_df = calc_zscores(jump_df)
    jump_df = calc_nm_profile(jump_df)
    return jump_df.sort_values(["Athlete", "Date"]).reset_index(drop=True)


def _records_to_jump_df(records: list[dict]) -> pd.DataFrame:
    """Consolida los tests individuales en una fila por atleta y fecha."""
    if not records:
        return pd.DataFrame()

    rows = {}
    for rec in records:
        athlete = str(rec.get("Athlete", "")).strip().title()
        date = pd.to_datetime(rec.get("Date"), errors="coerce")
        if not athlete or pd.isna(date):
            continue

        key = (athlete, date.normalize())
        row = rows.setdefault(key, {"Athlete": athlete, "Date": date.normalize()})
        for k, v in rec.items():
            if k in {"Athlete", "Date", "test_type"} or k.endswith("_reps"):
                continue
            if v is not None and not (isinstance(v, float) and np.isnan(v)):
                row[k] = v

    return _prepare_jump_df(pd.DataFrame(rows.values()))


def _get_secret_or_env(name: str, default=None):
    try:
        if name in st.secrets:
            return st.secrets[name]
    except Exception:
        pass
    return os.getenv(name, default)


def _supabase_evaluations_config() -> tuple[str | None, str | None, str]:
    url = (
        _get_secret_or_env("SUPABASE_URL")
        or _get_secret_or_env("THRESHOLD_SUPABASE_URL")
    )
    key = (
        _get_secret_or_env("SUPABASE_SERVICE_ROLE_KEY")
        or _get_secret_or_env("SUPABASE_KEY")
        or _get_secret_or_env("SUPABASE_ANON_KEY")
        or _get_secret_or_env("THRESHOLD_SUPABASE_KEY")
    )
    table = (
        _get_secret_or_env("SUPABASE_EVALUATIONS_TABLE")
        or SUPABASE_EVALUATIONS_TABLE
    )
    return url, key, table


def supabase_evaluations_enabled() -> bool:
    url, key, table = _supabase_evaluations_config()
    return bool(url and key and table)


def _supabase_request(method: str, table: str, query: dict | None = None,
                      payload: list[dict] | dict | None = None,
                      prefer: str | None = None):
    url, key, _ = _supabase_evaluations_config()
    if not url or not key:
        raise RuntimeError("Supabase no configurado")

    endpoint = f"{url.rstrip('/')}/rest/v1/{table}"
    if query:
        qs = urllib.parse.urlencode(query, doseq=True, safe="*,():")
        endpoint = f"{endpoint}?{qs}"

    headers = {
        "apikey": key,
        "Authorization": f"Bearer {key}",
    }
    if payload is not None:
        headers["Content-Type"] = "application/json"
    if prefer:
        headers["Prefer"] = prefer

    data = None
    if payload is not None:
        data = json.dumps(payload).encode("utf-8")

    request = urllib.request.Request(endpoint, data=data, headers=headers, method=method)
    try:
        with urllib.request.urlopen(request, timeout=20) as response:
            body = response.read().decode("utf-8", errors="ignore")
            if not body:
                return None
            return json.loads(body)
    except urllib.error.HTTPError as exc:
        detail = exc.read().decode("utf-8", errors="ignore")
        raise RuntimeError(f"{exc.code} {exc.reason}: {detail}") from exc
    except urllib.error.URLError as exc:
        raise RuntimeError(f"No se pudo conectar a Supabase: {exc.reason}") from exc


SUPABASE_DATASETS_TABLE = "dataset_rows"
REMOTE_DATASET_KEYS = ["rpe_df", "wellness_df", "completion_df", "rep_load_df", "raw_df", "maxes_df"]


def _supabase_dataset_store_config() -> tuple[str | None, str | None, str]:
    url = (
        _get_secret_or_env("SUPABASE_URL")
        or _get_secret_or_env("THRESHOLD_SUPABASE_URL")
    )
    key = (
        _get_secret_or_env("SUPABASE_SERVICE_ROLE_KEY")
        or _get_secret_or_env("SUPABASE_KEY")
        or _get_secret_or_env("SUPABASE_ANON_KEY")
        or _get_secret_or_env("THRESHOLD_SUPABASE_KEY")
    )
    table = (
        _get_secret_or_env("SUPABASE_DATASETS_TABLE")
        or SUPABASE_DATASETS_TABLE
    )
    return url, key, table


def supabase_dataset_store_enabled() -> bool:
    url, key, table = _supabase_dataset_store_config()
    return bool(url and key and table)


def _json_safe_value(value):
    if value is None or pd.isna(value):
        return None
    if isinstance(value, pd.Timestamp):
        return value.date().isoformat()
    if isinstance(value, np.datetime64):
        return pd.Timestamp(value).date().isoformat()
    if isinstance(value, (np.integer, int)):
        return int(value)
    if isinstance(value, (np.floating, float)):
        if not np.isfinite(value):
            return None
        return float(value)
    if isinstance(value, (np.bool_, bool)):
        return bool(value)
    return value


def _dataset_event_date(value) -> str | None:
    if value in [None, "", "â€”", "-"]:
        return None
    parsed = pd.to_datetime(value, errors="coerce")
    if pd.isna(parsed):
        return None
    return parsed.date().isoformat()


def _dataset_row_signature(state_key: str, payload: dict[str, object]) -> str:
    spec = DATASET_SPECS.get(state_key, {})
    dedupe_cols = spec.get("dedupe_cols") or sorted(payload.keys())
    key_payload = {col: payload.get(col) for col in dedupe_cols if col in payload}
    if not key_payload:
        key_payload = payload
    signature = json.dumps(key_payload, sort_keys=True, ensure_ascii=False, default=str)
    return hashlib.sha1(signature.encode("utf-8")).hexdigest()


def _dataset_df_to_remote_records(state_key: str, df: pd.DataFrame) -> list[dict]:
    if state_key not in REMOTE_DATASET_KEYS or df is None or df.empty:
        return []

    spec = DATASET_SPECS.get(state_key, {})
    date_col = spec.get("date_col")
    athlete_col = spec.get("athlete_col")
    records: list[dict] = []

    for _, row in df.iterrows():
        payload: dict[str, object] = {}
        for col in df.columns:
            safe_value = _json_safe_value(row.get(col))
            if safe_value is not None:
                payload[col] = safe_value

        if not payload:
            continue

        if athlete_col and athlete_col in payload:
            payload[athlete_col] = normalize_athlete_name(payload[athlete_col])

        record = {
            "dataset_key": state_key,
            "row_key": _dataset_row_signature(state_key, payload),
            "payload": payload,
        }

        if athlete_col and payload.get(athlete_col):
            record["athlete"] = normalize_athlete_name(payload[athlete_col])

        event_date = _dataset_event_date(payload.get(date_col)) if date_col else None
        if event_date:
            record["event_date"] = event_date

        records.append(record)

    return records


def save_remote_dataset(state_key: str, df: pd.DataFrame) -> dict[str, int | bool]:
    if not supabase_dataset_store_enabled() or state_key not in REMOTE_DATASET_KEYS:
        return {"enabled": False, "upserted": 0}

    payload = _dataset_df_to_remote_records(state_key, df)
    if not payload:
        return {"enabled": True, "upserted": 0}

    _, _, table = _supabase_dataset_store_config()
    rows = _supabase_request(
        "POST",
        table,
        query={"on_conflict": "dataset_key,row_key"},
        payload=payload,
        prefer="resolution=merge-duplicates,return=representation",
    ) or []
    return {"enabled": True, "upserted": len(rows) if rows else len(payload)}


def load_remote_dataset(state_key: str) -> pd.DataFrame:
    if not supabase_dataset_store_enabled() or state_key not in REMOTE_DATASET_KEYS:
        return pd.DataFrame()

    _, _, table = _supabase_dataset_store_config()
    rows = []
    offset = 0
    page_size = 1000

    while True:
        batch = _supabase_request(
            "GET",
            table,
            query={
                "select": "payload",
                "dataset_key": f"eq.{state_key}",
                "order": "event_date.asc.nullslast,row_key.asc",
                "limit": page_size,
                "offset": offset,
            },
        ) or []
        if not batch:
            break
        rows.extend(batch)
        if len(batch) < page_size:
            break
        offset += page_size

    payloads = [row.get("payload") for row in rows if isinstance(row.get("payload"), dict)]
    if not payloads:
        return pd.DataFrame()
    return pd.DataFrame(payloads)


def _jump_df_to_db_records(df: pd.DataFrame) -> list[dict]:
    if df is None or df.empty:
        return []

    records = []
    for _, row in df.iterrows():
        record = {}
        for app_col in EVALUATION_PERSIST_COLUMNS:
            if app_col not in row.index:
                continue
            value = row[app_col]
            if pd.isna(value):
                continue
            db_col = EVALUATION_DB_COLUMN_MAP[app_col]
            if app_col == "Date":
                record[db_col] = pd.Timestamp(value).date().isoformat()
            elif app_col == "Athlete":
                record[db_col] = str(value).strip().title()
            elif isinstance(value, (np.integer, int)):
                record[db_col] = int(value)
            elif isinstance(value, (np.floating, float)):
                record[db_col] = float(value)
            else:
                record[db_col] = value

        if record.get("athlete") and record.get("date"):
            records.append(record)
    return records


def save_evaluation(df: pd.DataFrame) -> dict:
    """Guarda evaluaciones en Supabase haciendo upsert por atleta+fecha."""
    if not supabase_evaluations_enabled():
        return {"enabled": False, "inserted": 0, "updated": 0, "total": 0}

    payload = _jump_df_to_db_records(df)
    if not payload:
        return {"enabled": True, "inserted": 0, "updated": 0, "total": 0}

    _, _, table = _supabase_evaluations_config()
    inserted = 0
    updated = 0

    for record in payload:
        filters = {
            "select": "athlete,date",
            "athlete": f"eq.{record['athlete']}",
            "date": f"eq.{record['date']}",
        }
        updated_rows = _supabase_request(
            "PATCH",
            table,
            query=filters,
            payload=record,
            prefer="return=representation",
        )
        if updated_rows:
            updated += len(updated_rows)
            continue

        inserted_rows = _supabase_request(
            "POST",
            table,
            payload=record,
            prefer="return=representation",
        )
        inserted += len(inserted_rows or [record])

    return {
        "enabled": True,
        "inserted": inserted,
        "updated": updated,
        "total": inserted + updated,
    }


def load_evaluations() -> pd.DataFrame:
    """Carga historial de evaluaciones desde Supabase como unica fuente de verdad."""
    if not supabase_evaluations_enabled():
        return pd.DataFrame()

    _, _, table = _supabase_evaluations_config()
    rows = []
    offset = 0
    page_size = 1000

    while True:
        batch = _supabase_request(
            "GET",
            table,
            query={
                "select": "*",
                "order": "date.asc,athlete.asc",
                "limit": page_size,
                "offset": offset,
            },
        ) or []
        if not batch:
            break
        rows.extend(batch)
        if len(batch) < page_size:
            break
        offset += page_size

    if not rows:
        return pd.DataFrame()

    rename_map = {db_col: app_col for app_col, db_col in EVALUATION_DB_COLUMN_MAP.items()}
    df = pd.DataFrame(rows).rename(columns=rename_map)
    keep_cols = [c for c in rename_map.values() if c in df.columns]
    return _prepare_jump_df(df[keep_cols])


def rename_evaluation_athlete_remote(old_name: str, new_name: str) -> dict[str, int | bool]:
    if not supabase_evaluations_enabled():
        return {"enabled": False, "updated": 0, "merged": 0, "deleted": 0}

    old_norm = normalize_athlete_name(old_name)
    new_norm = normalize_athlete_name(new_name)
    _, _, table = _supabase_evaluations_config()

    rows = _supabase_request(
        "GET",
        table,
        query={"select": "*", "athlete": f"eq.{old_norm}"},
    ) or []

    updated = 0
    merged = 0
    deleted = 0

    for row in rows:
        date_value = row.get("date")
        if not date_value:
            continue

        target_rows = _supabase_request(
            "GET",
            table,
            query={
                "select": "*",
                "athlete": f"eq.{new_norm}",
                "date": f"eq.{date_value}",
            },
        ) or []

        if target_rows:
            merged_row = target_rows[0].copy()
            for key, value in row.items():
                if key in {"athlete", "date"}:
                    continue
                if merged_row.get(key) in (None, "") and value not in (None, ""):
                    merged_row[key] = value

            _supabase_request(
                "PATCH",
                table,
                query={
                    "athlete": f"eq.{new_norm}",
                    "date": f"eq.{date_value}",
                },
                payload=merged_row,
                prefer="return=representation",
            )
            _supabase_request(
                "DELETE",
                table,
                query={
                    "athlete": f"eq.{old_norm}",
                    "date": f"eq.{date_value}",
                },
                prefer="return=representation",
            )
            merged += 1
            deleted += 1
            continue

        _supabase_request(
            "PATCH",
            table,
            query={
                "athlete": f"eq.{old_norm}",
                "date": f"eq.{date_value}",
            },
            payload={"athlete": new_norm},
            prefer="return=representation",
        )
        updated += 1

    return {"enabled": True, "updated": updated, "merged": merged, "deleted": deleted}


