def chart_cmj_trend(jump_df: pd.DataFrame, athlete: str) -> go.Figure:
    d = jump_df[jump_df["Athlete"] == athlete].sort_values("Date")
    if d.empty:
        return go.Figure()
    baseline = d["CMJ_cm"].mean()
    fig = go.Figure()
    fig.add_hrect(y0=baseline*0.95, y1=baseline*1.05,
                  fillcolor="rgba(111,143,120,0.10)", line_width=0,
                  annotation_text="±5% Baseline", annotation_font_color=C["gray"],
                  annotation_font_size=9)
    fig.add_hline(y=baseline, line_dash="dash", line_color=C["gray"],
                  annotation_text=f"BL {baseline:.1f}cm")
    fig.add_trace(go.Scatter(
        x=d["Date"], y=d["CMJ_cm"],
        mode="lines+markers",
        line=dict(color=C["steel"], width=2.5),
        marker=dict(size=8, color=[
            C["red"] if abs((v-baseline)/baseline*100) > 5 else C["green"]
            for v in d["CMJ_cm"]],
            line=dict(color=C["card"], width=1)),
        hovertemplate="%{x|%d/%m/%Y}<br>CMJ: %{y:.1f} cm<extra></extra>",
        name="CMJ",
    ))
    fig.update_layout(**_DARK, height=340,
                      title=dict(text=f"<b>Tendencia CMJ — {athlete}</b>",
                                 font=dict(color=C["navy"], size=13)),
                      xaxis=dict(title="Fecha", gridcolor=_GRID_SOFT, zeroline=False),
                      yaxis=dict(title="cm", gridcolor=_GRID_SOFT, zeroline=False))
    return fig


