def _read_xlsx_rows(file_bytes: bytes) -> list:
    with zipfile.ZipFile(BytesIO(file_bytes)) as z:
        ns = "http://schemas.openxmlformats.org/spreadsheetml/2006/main"
        with z.open("xl/sharedStrings.xml") as f:
            ss_tree = ET.parse(f)
            strings = []
            for si in ss_tree.findall(f".//{{{ns}}}si"):
                texts = si.findall(f".//{{{ns}}}t")
                strings.append("".join(t.text or "" for t in texts))
        with z.open("xl/worksheets/sheet1.xml") as f:
            tree = ET.parse(f)
            rows = []
            for row in tree.findall(f".//{{{ns}}}row"):
                cells = []
                for c in row.findall(f"{{{ns}}}c"):
                    t = c.get("t", "")
                    v_el = c.find(f"{{{ns}}}v")
                    if v_el is None:
                        cells.append("")
                    elif t == "s":
                        idx = int(v_el.text)
                        cells.append(strings[idx] if idx < len(strings) else "")
                    else:
                        cells.append(v_el.text or "")
                rows.append(cells)
    return rows


def _safe_float(val):
    try:
        return float(str(val).replace(",", "."))
    except Exception:
        return None


def _wellness_score(sueno, estres, dolor):
    vals = [v for v in [sueno, estres, dolor] if v is not None]
    return sum(vals) if vals else None


def _classify_acwr(v: float) -> str:
    if v == 0:           return "Sin carga"
    if v < 0.8:          return "Subcarga"
    if v <= 1.3:         return "Óptimo"
    if v <= 1.5:         return "Precaución"
    return "Alto riesgo"


def _acwr_color(v: float) -> str:
    z = _classify_acwr(v)
    return {"Sin carga": C["gray"], "Subcarga": C["blue"],
            "Óptimo": C["green"], "Precaución": C["yellow"],
            "Alto riesgo": C["red"]}.get(z, C["gray"])


def _alert(msg, level="g"):
    cls = {"g": "alert-g", "y": "alert-y", "r": "alert-r", "b": "alert-b"}.get(level, "alert-g")
    st.markdown(f'<div class="{cls}">{msg}</div>', unsafe_allow_html=True)


