def hydrate_local_store(force: bool = True):
    stored_state = load_recent_state(weeks=RECENT_WEEKS)
    for key, df in stored_state.items():
        current = st.session_state.get(key)
        should_replace = force or current is None or (hasattr(current, "empty") and current.empty)
        if should_replace:
            st.session_state[key] = df
    rebuild_load_state()


def hydrate_remote_datasets(force: bool = False, show_success: bool = False):
    if not supabase_dataset_store_enabled():
        return
    if st.session_state.datasets_loaded_from_store and not force:
        return

    try:
        synced_labels = []
        for state_key in REMOTE_DATASET_KEYS:
            remote_df = load_remote_dataset(state_key)
            if remote_df.empty:
                continue
            save_dataset(state_key, remote_df)
            synced_labels.append(f"{state_key}: {len(remote_df)}")

        if synced_labels:
            hydrate_local_store(force=True)
            if show_success:
                st.session_state.dataset_sync_notice = (
                    "Datasets TeamBuildr cargados desde Supabase: "
                    + ", ".join(synced_labels)
                )
                st.session_state.dataset_sync_notice_kind = "success"
        elif force and show_success:
            st.session_state.dataset_sync_notice = (
                "No hay datasets TeamBuildr guardados en Supabase todavia."
            )
            st.session_state.dataset_sync_notice_kind = "info"
    except Exception as exc:
        st.session_state.dataset_sync_notice = (
            f"No se pudieron sincronizar datasets TeamBuildr con Supabase: {exc}"
        )
        st.session_state.dataset_sync_notice_kind = "warning"
    finally:
        st.session_state.datasets_loaded_from_store = True


def hydrate_evaluations_from_store(force: bool = False, show_success: bool = False):
    if not supabase_evaluations_enabled():
        return
    if st.session_state.evaluations_loaded_from_store and not force:
        return

    try:
        remote_df = load_evaluations()
        if not remote_df.empty:
            save_dataset("jump_df", remote_df)
            persist_athlete_names(remote_df["Athlete"].dropna().tolist())
            recent_jump_df = load_recent_dataset("jump_df", weeks=RECENT_WEEKS)
            st.session_state.jump_df = recent_jump_df if not recent_jump_df.empty else None
            if show_success:
                st.session_state.eval_sync_notice = (
                    f"Historial de evaluaciones cargado desde Supabase "
                    f"({len(remote_df)} registros, ventana activa de {RECENT_WEEKS} semanas)."
                )
                st.session_state.eval_sync_notice_kind = "success"
        elif force and show_success:
            st.session_state.eval_sync_notice = "No hay evaluaciones guardadas en Supabase todavia."
            st.session_state.eval_sync_notice_kind = "info"
    except Exception as exc:
        st.session_state.eval_sync_notice = f"No se pudo sincronizar evaluaciones con Supabase: {exc}"
        st.session_state.eval_sync_notice_kind = "warning"
    finally:
        st.session_state.evaluations_loaded_from_store = True


