# TAB: REPORTE DESCARGABLE
# ─────────────────────────────────────────────────────────────────────
with tab_report:
    render_module_header("Reporte", "exportar datos para compartir con el cuerpo tecnico", kicker="Modulo")

    col_r1, col_r2 = st.columns(2)

    with col_r1:
        render_subsection_header("Contenido del reporte", "seleccion de bloques para exportacion", kicker="Exportacion")
        include_acwr     = st.checkbox("ACWR + sRPE diario", value=True)
        include_mono     = st.checkbox("Monotonia + strain semanal", value=True)
        include_wellness = st.checkbox("Wellness historico", value=True)
        include_jumps    = st.checkbox("Evaluaciones de saltos (EUR, DRI, Z-scores)", value=True)
        include_maxes    = st.checkbox("Progresion de maximos", value=True)
        include_volume   = st.checkbox("Volumen por sesion (Rep/Load)", value=True)
        include_completion = st.checkbox("Completion rate", value=True)

    with col_r2:
        render_subsection_header("Opciones", "alcance del archivo a exportar", kicker="Filtro")
        report_athlete = "Todos"
        audience_choice = st.selectbox(
            "Destinatario del PDF",
            list(REPORT_AUDIENCE_OPTIONS.keys()),
            index=1,
            key="sel_report_audience",
        )
        report_audience = normalize_report_audience(REPORT_AUDIENCE_OPTIONS[audience_choice])
        if (
            st.session_state.rpe_df is not None
            or st.session_state.jump_df is not None
            or st.session_state.maxes_df is not None
            or st.session_state.rep_load_df is not None
        ):
            athletes_r = collect_report_athletes(dict(st.session_state))
            report_athlete = st.selectbox(
                "Filtrar por atleta (opcional)",
                ["Todos"] + athletes_r, key="sel_report_ath")

    st.markdown("---")

    report_state = dict(st.session_state)
    executive_df = build_executive_summary_df(report_state, report_athlete)
    report_insights = generate_module_insights(report_state, report_athlete, report_audience)
    report_note = report_insights.get("report")
    profile_note = report_insights.get("profile")
    if report_audience in {"atleta", "cliente"} and report_athlete == "Todos":
        st.info("Para un PDF de atleta o cliente conviene elegir un atleta puntual para personalizar mejor el contenido.")

    render_subsection_header("Vista previa exportable", "bloques listos para excel y salida visual", kicker="Preview")
    if not executive_df.empty:
        st.dataframe(executive_df, use_container_width=False, hide_index=True)

    preview_left, preview_right = st.columns(2)
    with preview_left:
        if report_note:
            render_report_note(
                report_note["title"],
                report_note["summary"],
                report_note.get("focuses"),
                kicker="Reporte",
            )
    with preview_right:
        if profile_note:
            render_report_note(
                profile_note["title"],
                profile_note["summary"],
                profile_note.get("focuses"),
                kicker="Focos",
            )

    st.markdown("---")

    if st.button("Preparar exportables"):
        sheets = build_report_sheets(
            report_state,
            report_athlete,
            report_audience=report_audience,
            include_acwr=include_acwr,
            include_mono=include_mono,
            include_wellness=include_wellness,
            include_jumps=include_jumps,
            include_maxes=include_maxes,
            include_volume=include_volume,
            include_completion=include_completion,
        )

        # ACWR
        if include_acwr and st.session_state.acwr_dict:
            acwr_all = []
            for ath, adf in st.session_state.acwr_dict.items():
                adf_copy = adf.copy()
                adf_copy["Athlete"] = ath
                if report_athlete != "Todos" and ath != report_athlete:
                    continue
                acwr_all.append(adf_copy)
            if acwr_all:
                sheets["ACWR_sRPE"] = pd.concat(acwr_all).round(2)

        # Monotonía
        if include_mono and st.session_state.mono_dict:
            mono_all = []
            for ath, mdf in st.session_state.mono_dict.items():
                if report_athlete != "Todos" and ath != report_athlete:
                    continue
                mdf_copy = mdf.copy()
                mdf_copy["Athlete"] = ath
                mono_all.append(mdf_copy)
            if mono_all:
                sheets["Monotonia_Strain"] = pd.concat(mono_all).round(2)

        # Wellness
        if include_wellness and st.session_state.wellness_df is not None:
            wdf_r = st.session_state.wellness_df
            if report_athlete != "Todos":
                wdf_r = wdf_r[wdf_r["Athlete"] == report_athlete]
            sheets["Wellness"] = wdf_r.round(2)

        # Jumps
        if include_jumps and st.session_state.jump_df is not None:
            jdf_r = st.session_state.jump_df
            if report_athlete != "Todos":
                jdf_r = jdf_r[jdf_r["Athlete"] == report_athlete]
            sheets["Evaluaciones_Saltos"] = jdf_r.round(2)

        # Maxes
        if include_maxes and st.session_state.maxes_df is not None:
            max_df_r = st.session_state.maxes_df
            if report_athlete != "Todos" and "Athlete" in max_df_r.columns:
                max_df_r = max_df_r[max_df_r["Athlete"] == report_athlete]
            sheets["Maximos_Ejercicios"] = max_df_r

        # Volume
        if include_volume and st.session_state.rep_load_df is not None:
            rep_df_r = st.session_state.rep_load_df
            if report_athlete != "Todos" and "Athlete" in rep_df_r.columns:
                rep_df_r = rep_df_r[rep_df_r["Athlete"] == report_athlete]
            sheets["Volumen_Sesion"] = rep_df_r

        # Completion
        if include_completion and st.session_state.completion_df is not None:
            comp_df_r = st.session_state.completion_df
            if report_athlete != "Todos" and "Athlete" in comp_df_r.columns:
                filtered_comp = comp_df_r[comp_df_r["Athlete"] == report_athlete]
                if not filtered_comp.empty:
                    comp_df_r = filtered_comp
            sheets["Completion_Rate"] = comp_df_r

        if not sheets:
            _alert("No hay datos para exportar. Cargá archivos primero.", "y")
        else:
            excel_bytes = export_excel(sheets)
            pdf_bytes = generate_visual_report_pdf(report_state, report_athlete, report_audience)
            ath_label = report_athlete.replace(" ", "_") if report_athlete != "Todos" else "Equipo"
            audience_label = audience_choice.replace(" ", "_")
            dl_1, dl_2 = st.columns(2)
            with dl_1:
                st.download_button(
                    label="Descargar reporte Excel",
                    data=excel_bytes,
                    file_name=f"Threshold_SC_Reporte_{ath_label}.xlsx",
                    mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                )
            with dl_2:
                st.download_button(
                    label="Descargar reporte visual PDF",
                    data=pdf_bytes,
                    file_name=f"Threshold_SC_Reporte_{ath_label}_{audience_label}.pdf",
                    mime="application/pdf",
                )
            _alert(f"Reporte generado con {len(sheets)} hojas y un PDF para {audience_choice}.", "g")

    # ── Qué falta para el reporte completo ──
    st.markdown("---")
    render_subsection_header("Checklist de datos para reporte completo", "estado de las fuentes necesarias para una exportacion integral", kicker="Checklist")
    checklist = [
        ("RPE + Tiempo (sRPE, ACWR)", st.session_state.rpe_df is not None),
        ("Wellness 3 preguntas", st.session_state.wellness_df is not None),
        ("Completion rate", st.session_state.completion_df is not None),
        ("Rep/Load (volumen)", st.session_state.rep_load_df is not None),
        ("Raw workouts (por ejercicio/tag)", st.session_state.raw_df is not None),
        ("Máximos ejercicios", st.session_state.maxes_df is not None),
        ("Evaluaciones saltos (CMJ/SJ/DJ/IMTP)", st.session_state.jump_df is not None),
    ]
    for label, ok in checklist:
        state = "Activo" if ok else "Faltante"
        st.markdown(f"**{label}:** {state}")
